import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API_URL = 'http://localhost:5000/api/transactions';

function App() {
  const [transactions, setTransactions] = useState([]);
  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [loading, setLoading] = useState(true);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    description: '',
    category: 'Pemasukan',
    amount: ''
  });

  const fetchTransactions = async () => {
    try {
      setLoading(true);
      const response = await axios.get(API_URL);
      setTransactions(Array.isArray(response.data) ? response.data : []);
    } catch (error) {
      console.error("Gagal sinkronisasi data Flask:", error);
      setTransactions([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTransactions();
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleFormSubmit = async (e) => {
    e.preventDefault();
    if (!formData.description || !formData.amount) {
      alert("Deskripsi dan nominal wajib diisi!");
      return;
    }
    try {
      await axios.post(API_URL, {
        date: formData.date,
        description: formData.description,
        category: formData.category,
        amount: parseFloat(formData.amount)
      });
      setFormData({
        date: new Date().toISOString().split('T')[0],
        description: '',
        category: 'Pemasukan',
        amount: ''
      });
      fetchTransactions();
      alert("Transaksi sukses disimpan ke database!");
    } catch (error) {
      console.error("Error creating transaction:", error);
      alert("Gagal menyimpan ke MySQL!");
    }
  };

  // SISTEM PENGAMAN ANTI-BLANK (OPTIONAL CHAINING)
  const totalPemasukan = transactions?.filter?.(t => t.category === 'Pemasukan')
    ?.reduce((sum, t) => sum + parseFloat(t.amount || 0), 0) || 0;

  const totalPengeluaran = transactions?.filter?.(t => t.category === 'Pengeluaran')
    ?.reduce((sum, t) => sum + parseFloat(t.amount || 0), 0) || 0;

  const sisaSaldo = totalPemasukan - totalPengeluaran;

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center bg-gray-900 text-emerald-400 font-sans">
        <div className="text-lg font-bold animate-pulse">Menghubungkan ke Backend Flask & MySQL...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-900 text-gray-100 font-sans flex">
      
      {/* COMPONENT 1: SIDEBAR MEGAH */}
      <aside className="w-64 bg-gray-950 border-r border-gray-800 p-6 flex flex-col justify-between shrink-0">
        <div className="space-y-6">
          <div className="border-b border-gray-800 pb-4">
            <h1 className="text-xl font-black tracking-wider text-emerald-400">FINANCE APP</h1>
            <p className="text-xs text-gray-500 mt-1">Software Engineering Project</p>
          </div>
          <nav className="space-y-2 text-sm">
            <button onClick={() => setActiveMenu('dashboard')} className={`w-full text-left p-3 rounded-lg font-semibold transition-colors ${activeMenu === 'dashboard' ? 'bg-emerald-500 text-gray-950' : 'hover:bg-gray-800 text-gray-400'}`}>
              📊 Dashboard Finansial
            </button>
            <button onClick={() => setActiveMenu('riwayat')} className={`w-full text-left p-3 rounded-lg font-semibold transition-colors ${activeMenu === 'riwayat' ? 'bg-emerald-500 text-gray-950' : 'hover:bg-gray-800 text-gray-400'}`}>
              📜 Riwayat Transaksi ({transactions?.length || 0})
            </button>
          </nav>
        </div>
        <div className="text-xs text-gray-600 border-t border-gray-800 pt-4">
          Status Database: <span className="text-emerald-400 font-bold">Connected (200 OK)</span>
        </div>
      </aside>

      {/* MAIN CONTENT AREA */}
      <main className="flex-1 p-8 overflow-y-auto">
        <div className="max-w-5xl mx-auto space-y-6">
          
          {/* TOP BAR / STATS */}
          <header className="flex justify-between items-center bg-gray-800/40 border border-gray-800 p-4 rounded-xl">
            <div>
              <h2 className="text-2xl font-bold text-gray-100 capitalize">{activeMenu} Finansial</h2>
              <p className="text-xs text-gray-400 mt-0.5">Sistem Monitoring Kas Terintegrasi Database</p>
            </div>
            <div className="bg-gray-900 px-4 py-2 rounded-lg border border-gray-700 text-sm font-medium text-cyan-400">
              Sisa Saldo: Rp {sisaSaldo.toLocaleString('id-ID')}
            </div>
          </header>

          {activeMenu === 'dashboard' ? (
            <div className="space-y-6">
              {/* KARTU STATISTIK KAS */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-gradient-to-br from-gray-800 to-gray-900 p-6 rounded-xl border border-gray-700 shadow-xl">
                  <span className="text-xs font-bold text-emerald-400 tracking-wider uppercase">Total Pemasukan Bersih</span>
                  <p className="text-3xl font-black text-emerald-400 mt-2">Rp {totalPemasukan.toLocaleString('id-ID')}</p>
                  <div className="w-full bg-gray-950 h-2 rounded-full mt-4 overflow-hidden">
                    <div className="bg-emerald-500 h-full" style={{ width: `${totalPemasukan > 0 ? 100 : 0}%` }}></div>
                  </div>
                </div>

                <div className="bg-gradient-to-br from-gray-800 to-gray-900 p-6 rounded-xl border border-gray-700 shadow-xl">
                  <span className="text-xs font-bold text-rose-400 tracking-wider uppercase">Total Pengeluaran Kas</span>
                  <p className="text-3xl font-black text-rose-400 mt-2">Rp {totalPengeluaran.toLocaleString('id-ID')}</p>
                  <div className="w-full bg-gray-950 h-2 rounded-full mt-4 overflow-hidden">
                    <div className="bg-rose-500 h-full" style={{ width: `${totalPemasukan > 0 ? (totalPengeluaran / totalPemasukan) * 100 : 0}%` }}></div>
                  </div>
                </div>
              </div>

              {/* FORM TAMBAH DATA BARU */}
              <div className="bg-gray-800 p-6 rounded-xl border border-gray-700 shadow-lg">
                <h3 className="text-lg font-bold text-gray-200 mb-4 border-b border-gray-700 pb-2">Entri Transaksi Baru</h3>
                <form onSubmit={handleFormSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                  <div>
                    <label className="block text-gray-400 mb-1">Tanggal Input</label>
                    <input type="date" name="date" value={formData.date} onChange={handleInputChange} className="w-full bg-gray-900 border border-gray-700 rounded-lg p-2.5 text-white focus:outline-none focus:border-emerald-500" />
                  </div>
                  <div>
                    <label className="block text-gray-400 mb-1">Kategori Aliran Dana</label>
                    <select name="category" value={formData.category} onChange={handleInputChange} className="w-full bg-gray-900 border border-gray-700 rounded-lg p-2.5 text-white focus:outline-none focus:border-emerald-500">
                      <option value="Pemasukan">Pemasukan (Uang Masuk)</option>
                      <option value="Pengeluaran">Pengeluaran (Uang Keluar)</option>
                    </select>
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-gray-400 mb-1">Deskripsi Keterangan</label>
                    <input type="text" name="description" value={formData.description} onChange={handleInputChange} placeholder="Contoh: Pembayaran Jasa Pembuatan Website" className="w-full bg-gray-900 border border-gray-700 rounded-lg p-2.5 text-white focus:outline-none focus:border-emerald-500" />
                  </div>
                  <div className="md:col-span-2">
                    <label className="block text-gray-400 mb-1">Nominal Rupiah (Rp)</label>
                    <input type="number" name="amount" value={formData.amount} onChange={handleInputChange} placeholder="Masukkan angka nominal (Contoh: 50000)" className="w-full bg-gray-900 border border-gray-700 rounded-lg p-2.5 text-white focus:outline-none focus:border-emerald-500" />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-emerald-500 hover:bg-emerald-600 text-gray-950 font-black p-3 rounded-lg transition-colors text-base mt-2 shadow-md">
                    🚀 Simpan Transaksi Ke Database
                  </button>
                </form>
              </div>
            </div>
          ) : (
            /* COMPONENT: RIWAYAT TABEL TRANSAKSI */
            <div className="bg-gray-800 p-6 rounded-xl border border-gray-700 shadow-lg">
              <h3 className="text-lg font-bold text-gray-200 mb-4 border-b border-gray-700 pb-2">Log Riwayat Transaksi</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-left text-sm">
                  <thead className="bg-gray-900 text-gray-400">
                    <tr>
                      <th className="p-3 rounded-l-lg">Tanggal</th>
                      <th className="p-3">Keterangan</th>
                      <th className="p-3">Kategori</th>
                      <th className="p-3 rounded-r-lg text-right">Nominal</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-700/50">
                    {transactions?.length === 0 ? (
                      <tr>
                        <td colSpan="4" className="text-center p-8 text-gray-500 italic">Database kosong, silakan tambah data di menu dashboard.</td>
                      </tr>
                    ) : (
                      transactions?.map?.((t) => (
                        <tr key={t.id} className="hover:bg-gray-700/30 transition-colors">
                          <td className="p-3 whitespace-nowrap text-gray-400">{t.date}</td>
                          <td className="p-3 font-semibold text-gray-200">{t.description}</td>
                          <td className="p-3">
                            <span className={`px-2 py-0.5 rounded text-xs font-bold ${t.category === 'Pemasukan' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                              {t.category}
                            </span>
                          </td>
                          <td className={`p-3 text-right font-black ${t.category === 'Pemasukan' ? 'text-emerald-400' : 'text-rose-400'}`}>
                            Rp {parseFloat(t.amount || 0).toLocaleString('id-ID')}
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}

        </div>
      </main>
    </div>
  );
}

export default App;
